// Tool name maps per client.
const M46_CLAUDE_TOOL_MAP = {
  Bash: "bash",
  Read: "read",
  Edit: "edit",
  Write: "write",
  Grep: "grep",
  Glob: "glob",
  WebFetch: "web_fetch",
  WebSearch: "web_search",
  TodoWrite: "todo_write",
};
const M46_CURSOR_TOOL_MAP = {
  shell_command: "bash",
  run_command: "bash",
  read_file: "read",
  view_file: "read",
  edit_file: "edit",
  write_file: "write",
  search_codebase: "grep",
  list_dir: "glob",
};
const M46_CODEX_TOOL_MAP = { shell: "bash", apply_patch: "edit", view: "read" };
const M46_WINDSURF_TOOL_MAP = {
  run_command: "bash",
  execute_command: "bash",
  view_file: "read",
  read_file: "read",
  write_to_file: "write",
  write_file: "write",
  search_files: "grep",
  find_by_name: "glob",
};

function m46CanonicalToolName(raw, client) {
  if (!raw) return "other";
  let map;
  if (client === "cursor") map = M46_CURSOR_TOOL_MAP;
  else if (client === "codex") map = M46_CODEX_TOOL_MAP;
  else if (client === "windsurf") map = M46_WINDSURF_TOOL_MAP;
  // copilot deliberately falls through to the Claude map: its normalization
  // branch rewrites tool names to Claude canonical form before dispatch.
  else map = M46_CLAUDE_TOOL_MAP;
  if (map[raw]) return map[raw];
  if (client === "claude" && typeof raw === "string" && raw.startsWith("mcp__")) {
    return "mcp_" + raw.slice(5).replace(/__/g, "_");
  }
  return "other";
}

function m46ExtractFailureCode(success, exitCode, stderr, signal, durationMs, timeoutThresholdMs) {
  if (success) return null;
  const haystack = stderr || "";
  for (const [code, regexes] of M46_REGEX_BANK) {
    if (regexes.some((r) => r.test(haystack))) return code;
  }
  if (
    (signal === "SIGTERM" || signal === "SIGKILL") &&
    timeoutThresholdMs != null &&
    durationMs != null &&
    durationMs >= timeoutThresholdMs
  ) {
    return "timeout";
  }
  if (typeof exitCode === "number" && exitCode !== 0) return "exit_nonzero";
  return "unknown";
}

// Session buffer \u2014 keyed by session_id.
const M46_SESSIONS = new Map();
const M46_MAX_SESSIONS = 256;
const M46_EVICTION_AGE_MS = 6 * 60 * 60 * 1000;

function m46GetOrCreateBuffer(sessionId) {
  let buf = M46_SESSIONS.get(sessionId);
  if (!buf) {
    // Evict if needed.
    const now = Date.now();
    for (const [id, b] of M46_SESSIONS.entries()) {
      if (now - b.lastTouchedAt >= M46_EVICTION_AGE_MS) M46_SESSIONS.delete(id);
    }
    if (M46_SESSIONS.size >= M46_MAX_SESSIONS) {
      const oldest = [...M46_SESSIONS.entries()].sort(
        ([, a], [, b]) => a.lastTouchedAt - b.lastTouchedAt,
      )[0];
      if (oldest) M46_SESSIONS.delete(oldest[0]);
    }
    buf = {
      toolCallCount: 0,
      toolFailureCount: 0,
      toolFailureCodes: new Set(),
      perPair: new Map(),
      lastTouchedAt: now,
    };
    M46_SESSIONS.set(sessionId, buf);
  }
  return buf;
}

function m46RecordToolOutcome(sessionId, toolName, success, failureCode, filePath) {
  if (!sessionId) return;
  try {
    const buf = m46GetOrCreateBuffer(sessionId);
    buf.toolCallCount += 1;
    if (!success && failureCode && M46_FAILURE_CODES.has(failureCode)) {
      buf.toolFailureCount += 1;
      buf.toolFailureCodes.add(failureCode);
      const key = toolName + "|" + (filePath || "") + "|" + failureCode;
      buf.perPair.set(key, (buf.perPair.get(key) || 0) + 1);
    }
    buf.lastTouchedAt = Date.now();
  } catch {
    // Never break the hook on buffer errors.
  }
}

const COLD_PATH_TIMEOUT_MS = 200;
const MAX_CONTEXT_CHARS = 1500;
// M60: ceiling for full-body delta delivery (~3000 tokens), used only when the
