  view: "Read",
  edit: "Edit",
  create: "Write",
  bash: "Bash",
  powershell: "Bash",
  grep: "Grep",
  glob: "Glob",
  web_fetch: "WebFetch",
  // VS Code agent mode names (docs show both naming generations; unknown
